#include <stdio.h>
int main() {
    int T, n, x;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &x);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        int moves = 0;
        while (x < n) {
            x += a[x];
            moves++;
        }
        printf("%d\n", moves);
    }
    return 0;
}

