        T = parseInt(line);
    } else {
        input.push(line.split(' ').map(num => parseInt(num)));
    }
    i++;
    if (i === T * 3 + 1) {
        for (let j = 0; j < T; j++) {
            let n = input[j * 3][0];
            let x = input[j * 3][1];
            let a = input[j * 3 + 1];
            let moves = 0;
            while (x < n) {
                x += a[x];
                moves++;
            }
            console.log(moves);
        }
    }
});

